arguments.command:
mkdir -p /tmp/stackalloc-test && cd /tmp/stackalloc-test && dotnet new console --force -q && cat > Program.cs << 'EOF'
using System;

// Test stackalloc Span<nint> and Span<nuint>
Span<nint> signed = stackalloc nint[4];
Span<nuint> unsigned = stackalloc nuint[4];

for (int i = 0; i < 4; i++)
{
    signed[i] = (nint)(i * 10);
    unsigned[i] = (nuint)(i * 100);
}

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"Span<nint>:  [{string.Join(", ", signed.ToArray())}]");
Console.WriteLine($"Span<nuint>: [{string.Join(", ", unsigned.ToArray())}]");
EOF
dotnet run

